IF OBJECT_ID('dbo.Films', 'U') IS NOT NULL
    DROP TABLE dbo.Films;
GO


CREATE TABLE Films (
    Film_ID INT IDENTITY(1,1) PRIMARY KEY,  
    Title Varchar(200),
    Film_description Varchar(500),
    Category Varchar(100),
    Film_Length INT,
    Rating Varchar(20),
    Release_year INT, 
    Rrental_rate FLOAT,
    Last_update DATETIMEOFFSET NOT NULL,
);
GO

